#!/usr/bin/env node
/**
 * One-shot migration for the agent-name rename shipped in PR #34.
 *
 * Five plugin-shipped agents were renamed to match the symmetric
 * `{stack}-implementer` / `{stack}-reviewer` pattern used by every
 * other stack:
 *
 *   spring-boot-api-implementer  → spring-boot-implementer
 *   spring-boot-code-reviewer    → spring-boot-reviewer
 *   react-feature-implementer    → react-implementer
 *   react-code-reviewer          → react-reviewer
 *   mock-endpoint-implementer    → mock-implementer
 *
 * Workspace-local agents generated by /discover follow the pattern
 * `{workspace-slug}-{stack}-{role}.md`. The dispatch table now looks
 * up the SHORT name, so any pre-existing
 * `~/.claude/agents/{slug}-spring-boot-api-implementer.md` files no
 * longer match — dispatch falls through to the plugin default,
 * losing the workspace's tailored conventions.
 *
 * This script renames those files in place AND updates the
 * `name:` field in their frontmatter, so dispatch lights up again.
 *
 * Usage:
 *   node migrate-agent-names.js              # dry-run (default — prints what WOULD change)
 *   node migrate-agent-names.js --apply      # actually rename
 *   node migrate-agent-names.js --dir <path> # override agents dir (default: ~/.claude/agents)
 *
 * Exit 0 = clean, exit 1 = something went wrong.
 *
 * Zero dependencies — pure Node stdlib.
 */

const fs = require('fs');
const path = require('path');
const os = require('os');

// ─── Args ────────────────────────────────────────────────
const args = process.argv.slice(2);
const apply = args.includes('--apply');
const dirIdx = args.indexOf('--dir');
const agentsDir = dirIdx >= 0 && args[dirIdx + 1]
  ? args[dirIdx + 1]
  : path.join(os.homedir(), '.claude', 'agents');

// ─── Rename table ────────────────────────────────────────
// Each entry: old SUFFIX  → new SUFFIX. Suffix-match keeps the
// workspace slug prefix intact: `dal-spring-boot-api-implementer.md`
// → `dal-spring-boot-implementer.md`.
const RENAMES = [
  { from: 'spring-boot-api-implementer', to: 'spring-boot-implementer' },
  { from: 'spring-boot-code-reviewer',   to: 'spring-boot-reviewer'   },
  { from: 'react-feature-implementer',   to: 'react-implementer'      },
  { from: 'react-code-reviewer',         to: 'react-reviewer'         },
  { from: 'mock-endpoint-implementer',   to: 'mock-implementer'       },
];

// ─── Scan ────────────────────────────────────────────────
if (!fs.existsSync(agentsDir)) {
  console.log(`No agents directory at ${agentsDir} — nothing to migrate.`);
  process.exit(0);
}

const files = fs.readdirSync(agentsDir).filter(f => f.endsWith('.md'));
const planned = [];

for (const file of files) {
  const base = file.replace(/\.md$/, '');
  for (const { from, to } of RENAMES) {
    // Match files that END with the old suffix. Either the file IS
    // the old name (no workspace prefix) or has a `{slug}-` prefix.
    if (base === from || base.endsWith('-' + from)) {
      const newBase = base.slice(0, base.length - from.length) + to;
      planned.push({
        oldPath: path.join(agentsDir, file),
        newPath: path.join(agentsDir, newBase + '.md'),
        oldName: base,
        newName: newBase,
      });
      break;
    }
  }
}

// ─── Report + (optional) apply ──────────────────────────
if (planned.length === 0) {
  console.log(`Scanned ${files.length} agent file(s) in ${agentsDir}.`);
  console.log('Nothing to migrate — no legacy agent names found.');
  process.exit(0);
}

console.log(`Found ${planned.length} agent file(s) to migrate in ${agentsDir}:\n`);
for (const p of planned) {
  console.log(`  ${p.oldName}  →  ${p.newName}`);
}
console.log('');

if (!apply) {
  console.log('Dry-run only. Re-run with --apply to actually rename the files');
  console.log('and update their `name:` frontmatter.');
  process.exit(0);
}

let renamed = 0;
let failed = 0;
for (const p of planned) {
  try {
    // Refuse to clobber if the new name already exists.
    if (fs.existsSync(p.newPath)) {
      console.error(`  SKIP ${p.oldName} — destination already exists: ${p.newPath}`);
      failed++;
      continue;
    }

    // Update `name:` in frontmatter BEFORE moving so the file
    // and its declared name stay in sync at all times.
    const raw = fs.readFileSync(p.oldPath, 'utf8');
    const updated = raw.replace(
      new RegExp(`^name:\\s*${p.oldName}\\s*$`, 'm'),
      `name: ${p.newName}`
    );
    fs.writeFileSync(p.oldPath, updated, 'utf8');
    fs.renameSync(p.oldPath, p.newPath);
    console.log(`  RENAMED ${p.oldName}  →  ${p.newName}`);
    renamed++;
  } catch (e) {
    console.error(`  ERROR ${p.oldName}: ${e.message}`);
    failed++;
  }
}

console.log(`\nDone: ${renamed} renamed, ${failed} failed.`);
process.exit(failed > 0 ? 1 : 0);
